function key(s: string | null | undefined): string {
  return (s || "")
    .toLowerCase().trim().replace(/&/g, "and")
    .replace(/[.\u2019']/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ").trim();
}

/** Trim + collapse whitespace; title-case only all-upper / all-lower input. */
function clean(s: string | null | undefined): string {
  const t = (s || "").replace(/\s+/g, " ").trim();
  if (!t) return t;
  if (t === t.toUpperCase() || t === t.toLowerCase()) {
    return t.split(" ").filter(Boolean).map((w) => w[0].toUpperCase() + w.slice(1).toLowerCase()).join(" ");
  }
  return t;
}

export interface NormalizedLocation {
  city: string | null;
  state: string | null;
  country: string | null;
  countryCode: string | null; // ISO-3166 alpha-2, lowercase (e.g. "us"); null if unknown
  location: string;           // composed display string
}

export function normalizeCountry(raw: string | null | undefined): { name: string | null; code: string | null } {
  if (!raw || !String(raw).trim()) return { name: null, code: null };
  const code = KEY_TO_CODE[key(raw)];
  if (code) return { name: CODE_TO_NAME[code], code };
  return { name: clean(raw), code: null };
}

export function normalizeRegion(raw: string | null | undefined, code: string | null): string | null {
  if (!raw || !String(raw).trim()) return null;
  const k = key(raw);
  if (code === "us") return US_STATE_KEY[k] ?? clean(raw);
  if (code === "ca") return CA_PROV_KEY[k] ?? clean(raw);
  return clean(raw);
}

export function normalizeCity(raw: string | null | undefined): string | null {
  return clean(raw) || null;
}

export function normalizeName(raw: string | null | undefined): string {
  return clean(raw) || "";
}

export function buildLocation(
  city: string | null, region: string | null, countryName: string | null, code: string | null,
): string {
  const parts: string[] = [];
  if (city) parts.push(city);
  if (region) parts.push(region);
  if (code !== "us" && countryName) parts.push(countryName);
  return parts.join(", ");
}

/** Normalize raw stored values into canonical fields + display location. */
export function normalizeLocation(
  city: string | null | undefined,
  state: string | null | undefined,
  country: string | null | undefined,
): NormalizedLocation {
  const { name, code } = normalizeCountry(country);
  const c = normalizeCity(city);
  const r = normalizeRegion(state, code);
  return { city: c, state: r, country: name, countryCode: code, location: buildLocation(c, r, name, code) };
}

/** Public path to the self-hosted 3x2 flag SVG, or null if country unknown. */
export function flagSrc(code: string | null): string | null {
  return code ? `/flags/3x2/${code.toUpperCase()}.svg` : null;
}
